const item = $input.first();
const body = item?.json?.body || {};
const errors = [];

function text(name) { return String(body[name] ?? '').trim(); }
function optionalBoolean(name) {
  const raw = body[name];
  if (raw === undefined || raw === null || raw === '') return true;
  const v = String(raw).trim().toLowerCase();
  return ['true','false','1','0','yes','no','si','s','n','on','off'].includes(v);
}

if (!text('email_to')) errors.push('email_to es obligatorio para llamadas webhook.');
for (const name of ['include_attachment','include_detail','include_summary','send_email']) {
  if (!optionalBoolean(name)) errors.push(`${name} debe ser booleano compatible: true/false, 1/0, si/no.`);
}
const valid = errors.length === 0;
return [{ json: { ...(item.json || {}), webhook_contract: { valid, status_code: valid ? 202 : 400, message: valid ? 'Workflow accepted' : errors.join(' '), errors } }, binary: item.binary }];

const item = $input.first();
const json = item?.json || {};
if (!json.webhook_contract?.valid) return [];
const { webhook_contract, ...cleanJson } = json;
return [{ json: cleanJson, binary: item.binary }];

const base = $input.first()?.json || {};
const trigger = $('SetTrigger - Flujo').first()?.json || {};

function normalizeBoolean(value, fallback) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const text = String(value).trim().toLowerCase();
  if (['true','1','yes','y','si','s','on','enabled'].includes(text)) return true;
  if (['false','0','no','n','off','disabled'].includes(text)) return false;
  return fallback;
}

const effectiveOrganization = trigger.itop_organization || trigger.organization || base.itop_organization || base.organization || base.config?.itop_organization || base.config?.itop?.organization || '';
const flags = { ...(base.flags || {}) };
for (const key of ['include_attachment','include_detail','include_summary','include_itop_button_footer','send_email']) {
  flags[key] = normalizeBoolean(trigger[key] ?? base[key], flags[key] ?? true);
}

const config = {
  itop_organization: effectiveOrganization,
  organization: effectiveOrganization,
  zonaHoraria: trigger.timezone || base.timezone || 'America/Santiago',
  nombreReporte: 'ad_itop_endpoint_pc_laptop_comparacion',
  ldap: {
    baseDn: trigger.ldap_base_dn,
    filter: trigger.ldap_filter,
    attributes: trigger.ldap_attributes,
    includedOus: String(trigger.ldap_included_ous || '').split(',').map(x => x.trim()).filter(Boolean)
  },
  itop: {
    pcClass: trigger.itop_pc_class || 'PC',
    laptopClass: trigger.itop_laptop_class || 'Laptop',
    oqlPC: trigger.itop_oql_pc || 'SELECT PC',
    oqlLaptop: trigger.itop_oql_laptop || 'SELECT Laptop',
    fields: trigger.itop_output_fields || 'name,friendlyname,status,serialnumber,asset_number,org_id,org_id_friendlyname,finalclass,description,location_id_friendlyname,brand_id_friendlyname,model_id_friendlyname'
  },
  mail: {
    from: trigger.email_from,
    to: trigger.email_to,
    cc: trigger.email_cc || '',
    bcc: trigger.email_bcc || '',
    subject: trigger.email_subject || 'Comparacion AD vs iTop - Endpoint PC/Laptop'
  }
};

const errors = [];
function required(path, value) { if (value === undefined || value === null || String(value).trim() === '') errors.push(`Parametro obligatorio no informado: ${path}`); }
required('ldap_base_dn', config.ldap.baseDn);
required('ldap_filter', config.ldap.filter);
required('ldap_attributes', config.ldap.attributes);
required('email_from', config.mail.from);
required('email_to', config.mail.to);
if (!config.ldap.includedOus.length) errors.push('ldap_included_ous debe contener al menos una OU relativa bajo SITES_CHILE.');
if (errors.length) throw new Error(errors.join(' | '));

flags.include_itop_button_footer = false;
return [{ json: { ...base, ...trigger, itop_organization: effectiveOrganization, organization: effectiveOrganization, flags, config, config_validated: true, include_itop_button_footer: false } }];

const cfg = $('Config Reporte').first().json.config;
const included = (cfg.ldap.includedOus || []).map(x => String(x).trim().toLowerCase()).filter(Boolean);

function clean(v) {
  if (v === undefined || v === null) return '';
  if (Array.isArray(v)) v = v[0] ?? '';
  return String(v).trim();
}
function hasClass(j, name) {
  const oc = j.objectClass;
  const arr = Array.isArray(oc) ? oc : String(oc || '').split(',');
  return arr.map(x => String(x).toLowerCase()).includes(String(name).toLowerCase());
}
function isDisabled(uac) {
  const n = Number(clean(uac));
  return Number.isFinite(n) && (n & 2) === 2;
}
function filetimeToDate(value) {
  const raw = clean(value);
  if (!raw || raw === '0') return null;
  const n = Number(raw);
  if (!Number.isFinite(n) || n <= 0) return null;
  const ms = Math.floor(n / 10000 - 11644473600000);
  const d = new Date(ms);
  return Number.isNaN(d.getTime()) ? null : d;
}
function fmtDate(value) {
  const d = value instanceof Date ? value : filetimeToDate(value);
  if (!d) return '-';
  return d.toLocaleString('es-CL', { timeZone: cfg.zonaHoraria || 'America/Santiago', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
}
function hostnameOf(j) {
  const raw = clean(j.dNSHostName || j.dnshostname || j.name || j.cn || j.sAMAccountName || j.samaccountname).replace(/\$$/, '');
  return raw.split('.')[0].trim().toUpperCase();
}
function ouRelative(dn) {
  const parts = clean(dn).split(',').map(x => x.trim()).filter(x => /^OU=/i.test(x));
  return parts.join(',');
}
function ouNames(dn) {
  return clean(dn).split(',').map(x => x.trim()).filter(x => /^OU=/i.test(x)).map(x => x.replace(/^OU=/i, '').toLowerCase());
}
function inIncludedOu(dn) {
  const names = ouNames(dn);
  return included.some(ou => names.includes(ou));
}
function subtype(host) {
  if (host.endsWith('-L')) return 'Laptop';
  if (host.endsWith('-D')) return 'Desktop';
  if (host.endsWith('-T')) return 'Tablet';
  if (host.endsWith('-V')) return 'Virtual';
  return 'Validar';
}
function prefixClass(host) {
  const h = clean(host).toUpperCase();
  if (h.startsWith('GF0')) return 'ENDPOINT';
  if (h.startsWith('GFPE')) return 'SERVIDOR';
  return 'REVISAR';
}

const endpoints = [];
const descartados = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const dn = clean(j.distinguishedName || j.dn);
  const sam = clean(j.sAMAccountName || j.samaccountname);
  const host = hostnameOf(j);
  const computerLike = hasClass(j, 'computer') || sam.endsWith('$') || Boolean(j.dNSHostName || j.dnshostname);
  if (!computerLike) continue;

  if (!inIncludedOu(dn)) {
    descartados.push({ hostname: host, motivo: 'Fuera de OU incluidas', dn });
    continue;
  }

  // Para conciliaciÃ³n 1 a 1 se consideran equipos AD activos e inactivos.
  // No se excluye por prefijo: GF0=ENDPOINT, GFPE=SERVIDOR, otro=REVISAR.
  // No se valida subtipo AD como regla de alcance; el sufijo se informa solo como dato operativo.
  const status = isDisabled(j.userAccountControl) ? 'INACTIVO' : 'ACTIVO';
  const clasificacionPrefijo = prefixClass(host);
  endpoints.push({
    hostname: host,
    ad_status: status,
    ad_status_raw: clean(j.userAccountControl),
    clasificacion_prefijo: clasificacionPrefijo,
    subtipo: subtype(host),
    lastLogon: fmtDate(j.lastLogonTimestamp || j.lastLogon),
    ou_relativa: ouRelative(dn),
    distinguishedName: dn,
    dnsHostName: clean(j.dNSHostName || j.dnshostname),
    operatingSystem: clean(j.operatingSystem),
    operatingSystemVersion: clean(j.operatingSystemVersion),
    managedBy: clean(j.managedBy),
    location: clean(j.location),
    description: clean(j.description || j.info),
    whenChanged: clean(j.whenChanged),
    whenCreated: clean(j.whenCreated)
  });
}
return [{ json: { adEndpoints: endpoints, adDiscarded: descartados } }];

const cfg = $('Config Reporte').first().json.config;

function clean(v) {
  if (v === undefined || v === null) return '';
  if (Array.isArray(v)) v = v[0] ?? '';
  return String(v).trim();
}
function flattenInput(items) {
  const rows = [];
  for (const item of items) {
    const j = item.json || {};
    if (j.objects && typeof j.objects === 'object') {
      for (const [key, value] of Object.entries(j.objects)) rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      continue;
    }
    if (j.data?.objects && typeof j.data.objects === 'object') {
      for (const [key, value] of Object.entries(j.data.objects)) rows.push({ key, ...(value || {}), fields: value?.fields || value || {} });
      continue;
    }
    if (Array.isArray(j)) { rows.push(...j); continue; }
    rows.push(j);
  }
  return rows;
}
function getField(obj, names, fallback = '') {
  for (const name of names) {
    if (obj && obj[name] !== undefined && obj[name] !== null && obj[name] !== '') return obj[name];
    if (obj?.fields && obj.fields[name] !== undefined && obj.fields[name] !== null && obj.fields[name] !== '') return obj.fields[name];
  }
  return fallback;
}
function hostnameFrom(value) {
  const raw = clean(value).replace(/\$$/, '');
  return raw.split('.')[0].trim().toUpperCase();
}
function normalizeStatus(value, friendlyValue = '') {
  const rawCode = clean(value);
  const rawFriendly = clean(friendlyValue);
  const raw = rawFriendly || rawCode;
  const values = [rawCode, rawFriendly].map(v => v.toLowerCase()).filter(Boolean);
  const has = (items) => values.some(v => items.includes(v));

  // Estados reales iTop para clase PC/Laptop:
  // En Inventario (stock), No Productivo (implementation), Productivo (production), Obsoleto (obsolete).
  if (has(['production','produccion','producción','in production','en produccion','en producción','productivo'])) {
    return { normalized: 'ACTIVO', raw: raw || 'Productivo' };
  }
  if (has(['stock','en stock','en inventario','inventario'])) {
    return { normalized: 'ACTIVO', raw: raw || 'En Inventario' };
  }
  if (has(['obsolete','obsoleto'])) {
    return { normalized: 'INACTIVO', raw: raw || 'Obsoleto' };
  }
  if (has(['implementation','implementacion','implementación','in implementation','en implementacion','en implementación','no productivo'])) {
    return { normalized: 'VALIDAR', raw: raw || 'No Productivo' };
  }
  if (!raw) {
    return { normalized: 'VALIDAR', raw: '-' };
  }
  return { normalized: 'INACTIVO', raw };
}

const rows = flattenInput($input.all());
const assets = [];
for (const row of rows) {
  const f = row.fields || row;
  const host = hostnameFrom(getField(f, ['name', 'friendlyname', 'hostname', 'serialnumber'], ''));
  if (!host) continue;
  const status = normalizeStatus(getField(f, ['status'], ''), getField(f, ['status_friendlyname'], ''));
  const finalclass = clean(getField(f, ['finalclass', 'class'], row.class || '')) || 'PC/Laptop';
  assets.push({
    hostname: host,
    itop_status: status.normalized,
    itop_status_raw: status.raw,
    itop_class: finalclass,
    itop_key: clean(row.key || row.id || getField(f, ['id', '_key', 'key'], '')),
    friendlyname: clean(getField(f, ['friendlyname'], '')),
    serialnumber: clean(getField(f, ['serialnumber', 'serial_number'], '')),
    asset_number: clean(getField(f, ['asset_number', 'assetnumber'], '')),
    org_name: clean(getField(f, ['org_id_friendlyname', 'org_name'], '')),
    location: clean(getField(f, ['location_id_friendlyname', 'location_name'], '')),
    brand: clean(getField(f, ['brand_id_friendlyname', 'brand_name'], '')),
    model: clean(getField(f, ['model_id_friendlyname', 'model_name'], ''))
  });
}
return [{ json: { itopAssets: assets } }];

const cfg = $('Config Reporte').first().json.config;
const input = $input.first().json || {};
const organization = clean(input.itop_organization || input.organization || cfg.itop_organization || cfg.organization || cfg.itop?.organization || '');
const adEndpointsRaw = input.adEndpoints || [];
const itopAssetsRaw = input.itopAssets || [];
const adDiscarded = input.adDiscarded || [];

function isGfpeHost(value) {
  return String(value ?? '').trim().toUpperCase().startsWith('GFPE');
}

// Este reporte compara endpoints PC/Laptop; se omiten equipos con prefijo GFPE.
const adEndpoints = adEndpointsRaw.filter(x => !isGfpeHost(x.hostname));
const itopAssets = itopAssetsRaw.filter(x => !isGfpeHost(x.hostname));

function clean(v) { return String(v ?? '').trim(); }
function add(map, key, value) { if (!map.has(key)) map.set(key, []); map.get(key).push(value); }
function esc(value) { return String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;').replace(/'/g, '&#039;'); }
function csvEscape(value) { return `"${String(value ?? '').replace(/"/g, '""')}"`; }

const adByHost = new Map();
const itopByHost = new Map();
for (const a of adEndpoints) add(adByHost, a.hostname, a);
for (const a of itopAssets) add(itopByHost, a.hostname, a);

function prefixClass(host) {
  const h = clean(host).toUpperCase();
  if (h.startsWith('GF0')) return 'ENDPOINT';
  if (h.startsWith('GFPE')) return 'SERVIDOR';
  return 'REVISAR';
}

function resolveTipo(host, ad, itop) {
  // Tipo visual del equipo segun nomenclatura. La regla de alcance AD se valida por prefijo:
  // GF0=Endpoint, GFPE=Servidor, otro=Revisar. No se usa el subtipo AD como criterio de exclusion.
  const h = clean(host).toUpperCase();
  if (h.endsWith('-L')) return 'Laptop';
  if (h.endsWith('-D')) return 'Desktop';
  if (h.endsWith('-V')) return 'Virtual';
  if (h.endsWith('-T')) return 'Tablet';

  // Fallback iTop: solo para registros sin sufijo suficiente o SOLO_ITOP.
  const rawClass = clean(itop?.itop_class || '').toLowerCase();
  if (rawClass === 'laptop') return 'Laptop';
  if (rawClass === 'pc') return 'PC';

  return 'Validar';
}

const allHosts = new Set([...adByHost.keys(), ...itopByHost.keys()].filter(Boolean));
const rows = [];
let sincronizados = 0;
let diferencias = 0;
let soloAD = 0;
let soloITop = 0;
let revisar = 0;
let duplicados = 0;

for (const host of [...allHosts].sort()) {
  const adList = adByHost.get(host) || [];
  const itopList = itopByHost.get(host) || [];
  if (adList.length > 1 || itopList.length > 1) duplicados++;
  const ad = adList[0] || null;
  const itop = itopList[0] || null;
  let estado = '';
  let observacion = '';
  if (ad && itop) {
    if (itop.itop_status === 'VALIDAR') {
      estado = 'REVISAR_ESTADO_ITOP'; revisar++;
      observacion = `Equipo encontrado en ambos sistemas. iTop informa estado real ${itop.itop_status_raw || '-'}, clasificado como VALIDAR para revision operativa frente al estado AD=${ad.ad_status}.`;
    } else if (ad.ad_status === itop.itop_status) {
      estado = 'SINCRONIZADO'; sincronizados++;
      observacion = `Sincronizado: AD=${ad.ad_status}, iTop=${itop.itop_status}. Estado real iTop: ${itop.itop_status_raw || '-'}.`;
    } else {
      estado = 'DIFERENCIA_ESTADO'; diferencias++;
      observacion = `Diferencia de estado: AD=${ad.ad_status}; iTop=${itop.itop_status}. Estado real iTop: ${itop.itop_status_raw || '-'}.`;
    }
  } else if (ad && !itop) {
    estado = 'SOLO_AD'; soloAD++;
    observacion = 'Equipo existe en AD dentro del alcance configurado, pero no existe como PC/Laptop en iTop por hostname. Se considera su estado AD real para conciliacion.';
  } else if (!ad && itop) {
    estado = 'SOLO_ITOP'; soloITop++;
    observacion = `Equipo existe en iTop PC/Laptop, pero no fue encontrado en AD dentro del alcance configurado. Estado real iTop: ${itop.itop_status_raw || '-'}.`;
  }
  if (adList.length > 1) observacion += ` Duplicado AD: ${adList.length} registros con mismo hostname.`;
  if (itopList.length > 1) observacion += ` Duplicado iTop: ${itopList.length} registros con mismo hostname.`;
  rows.push({
    Hostname: host,
    Tipo: resolveTipo(host, ad, itop),
    'Clasificacion Prefijo': ad?.clasificacion_prefijo || prefixClass(host),
    'AD Status': String(ad?.ad_status || 'NO_ENCONTRADO').toUpperCase(),
    'iTop Status': String(itop?.itop_status || 'NO_ENCONTRADO').toUpperCase(),
    'iTop Status Real': itop?.itop_status_raw || '',
    Estado: estado,
    Observacion: observacion,
    Subtipo: ad?.subtipo || '',
    'LastLogon AD': ad?.lastLogon || '-',
    'OU AD': ad?.ou_relativa || '',
    'SO AD': ad?.operatingSystem || '',
    'DNSHostName AD': ad?.dnsHostName || '',
    'Clase iTop': itop?.itop_class || '',
    'Serial iTop': itop?.serialnumber || '',
    'Asset Number iTop': itop?.asset_number || '',
    'Org iTop': itop?.org_name || '',
    'Ubicacion iTop': itop?.location || '',
    'Key iTop': itop?.itop_key || ''
  });
}

const resumen = {
  fecha_ejecucion: new Date().toISOString(),
  total_ad_equipos: adEndpoints.length,
  total_ad_activos: adEndpoints.filter(x => x.ad_status === 'ACTIVO').length,
  total_ad_inactivos: adEndpoints.filter(x => x.ad_status === 'INACTIVO').length,
  total_itop_pc_laptop: itopAssets.length,
  sincronizados,
  sincronizados_activos: rows.filter(r => r.Estado === 'SINCRONIZADO' && r['AD Status'] === 'ACTIVO').length,
  sincronizados_inactivos: rows.filter(r => r.Estado === 'SINCRONIZADO' && r['AD Status'] === 'INACTIVO').length,
  diferencias_estado: diferencias,
  solo_ad: soloAD,
  solo_itop: soloITop,
  revisar,
  duplicados,
  descartados_ad: adDiscarded.length
};
const hayDiferencias = diferencias + soloAD + soloITop + revisar + duplicados > 0;

const estadoOrden = {
  DIFERENCIA_ESTADO: 10,
  SOLO_AD: 20,
  SOLO_ITOP: 30,
  REVISAR_ESTADO_ITOP: 40,
  SINCRONIZADO: 90
};
function sincronizadoOrden(row) {
  if (row.Estado !== 'SINCRONIZADO') return 0;
  if (row['AD Status'] === 'ACTIVO') return 1;
  if (row['AD Status'] === 'INACTIVO') return 2;
  return 3;
}
rows.sort((a, b) => {
  const oa = estadoOrden[a.Estado] ?? 80;
  const ob = estadoOrden[b.Estado] ?? 80;
  if (oa !== ob) return oa - ob;
  const sa = sincronizadoOrden(a);
  const sb = sincronizadoOrden(b);
  if (sa !== sb) return sa - sb;
  return String(a.Hostname || '').localeCompare(String(b.Hostname || ''));
});

const csvHeaders = ['Hostname','Tipo','Clasificacion Prefijo','AD Status','iTop Status','iTop Status Real','Estado','Observacion','Subtipo','LastLogon AD','OU AD','SO AD','DNSHostName AD','Clase iTop','Serial iTop','Asset Number iTop','Org iTop','Ubicacion iTop','Key iTop'];
const csv = '\uFEFF' + [csvHeaders.map(csvEscape).join(';'), ...rows.map(r => csvHeaders.map(h => csvEscape(r[h])).join(';'))].join('\r\n');
const stamp = new Date().toISOString().replace(/[:.]/g, '-').replace('T', '_').slice(0, 19);

function displayEstado(estado) {
  const labels = {
    SINCRONIZADO: 'Sincronizado',
    DIFERENCIA_ESTADO: 'Diferencia de estado',
    SOLO_AD: 'Solo en AD',
    SOLO_ITOP: 'Solo en iTop',
    REVISAR_ESTADO_ITOP: 'Revisar estado iTop',
    SIN_DATOS: 'Sin datos'
  };
  return labels[estado] || String(estado || '-');
}
function td(v) { return `<td style="font-size:12px;line-height:16px;color:#1f2937;padding:8px;border-bottom:1px solid #e5e7eb;vertical-align:top;">${v}</td>`; }
function th(v) { return `<th align="left" style="font-size:11px;color:#334155;background:#f1f5f9;padding:8px;border-bottom:1px solid #cbd5e1;">${esc(v)}</th>`; }
function renderRow(r) {
  return `<tr>${td(`<strong>${esc(r.Hostname)}</strong>`)}${td(esc(r.Tipo || 'Validar'))}${td(esc(r['AD Status']))}${td(esc(r['iTop Status']))}${td(esc(displayEstado(r.Estado)))}${td(esc(r.Observacion))}</tr>`;
}
function renderGroup(title, list) {
  if (!list.length) return '';
  return `<tr><td colspan="6" style="font-size:12px;font-weight:bold;color:#0f172a;background:#e2e8f0;padding:8px;border-bottom:1px solid #cbd5e1;">${esc(title)} (${list.length})</td></tr>${list.map(renderRow).join('')}`;
}
const gruposDetalle = [
  ['DIFERENCIAS - Casos a analizar', rows.filter(r => r.Estado === 'DIFERENCIA_ESTADO')],
  ['SOLO AD - Casos a analizar', rows.filter(r => r.Estado === 'SOLO_AD')],
  ['SOLO ITOP - Casos a analizar', rows.filter(r => r.Estado === 'SOLO_ITOP')],
  ['REVISAR - Casos a analizar', rows.filter(r => r.Estado === 'REVISAR_ESTADO_ITOP')],
  ['Correctos - Sincronizados activos', rows.filter(r => r.Estado === 'SINCRONIZADO' && r['AD Status'] === 'ACTIVO')],
  ['Correctos - Sincronizados inactivos', rows.filter(r => r.Estado === 'SINCRONIZADO' && r['AD Status'] === 'INACTIVO')],
  ['Correctos - Sincronizados otros estados', rows.filter(r => r.Estado === 'SINCRONIZADO' && !['ACTIVO','INACTIVO'].includes(r['AD Status']))],
];
const detailRows = gruposDetalle.map(([title, list]) => renderGroup(title, list)).join('') || `<tr>${td('Sin registros para mostrar.')}${td('-')}${td('-')}${td('-')}${td(esc(displayEstado('SIN_DATOS')))}${td('No se recibieron equipos desde AD ni desde iTop para el alcance configurado.')}</tr>`;

const generatedAt = new Date().toLocaleString('es-CL', { timeZone: cfg.zonaHoraria || 'America/Santiago', year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit' });
const subject = `${cfg.mail.subject} - ${hayDiferencias ? 'Con diferencias' : 'Sin diferencias'}`;
const html = '';

return [{
  json: {
    ...input,
    resumen,
    rows,
    hayDiferencias,
    email_from: cfg.mail.from,
    email_to: cfg.mail.to,
    email_cc: cfg.mail.cc,
    email_bcc: cfg.mail.bcc,
    email_subject: subject,
    report_template_key: input.report_template_key || 'ad-itop-endpoint-pc-laptop-comparacion',
    report_title: 'Comparacion AD vs iTop - Endpoint PC/Laptop',
    report_description: 'Vista de conciliacion entre el inventario de endpoints en Active Directory y los activos PC/Laptop registrados en iTop, orientada a detectar brechas de sincronizacion y priorizar acciones de regularizacion.',
    generated_at: generatedAt,
    company: input.Company || input.company || 'TecnoComp',
    Company: input.Company || input.company || 'TecnoComp',
    itop_organization: organization || '-',
    total_ad_equipos: String(resumen.total_ad_equipos),
    total_ad_activos: String(resumen.total_ad_activos),
    total_ad_inactivos: String(resumen.total_ad_inactivos),
    total_itop_pc_laptop: String(resumen.total_itop_pc_laptop),
